// ---- Pillar 3: Sitemap Crawler — daily competitor URL discovery ----
// For each competitor domain, fetch sitemap.xml + sitemap_index.xml
// Parse <loc> tags via regex → batch-check Supabase for new URLs
// POST each new URL to content-extractor webhook
// Architecture: Promise.allSettled per domain — one domain failure doesn't block others
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;

const COMPETITORS = [
  'gotomarket.io', 'revenuearchitects.com', 'growthcollective.com',
  'pavilion.com', 'klique.io', 'demandcurve.com', 'cxl.com', 'openviewpartners.com'
];

const SITEMAP_PATHS = ['/sitemap.xml', '/sitemap_index.xml', '/sitemap-index.xml', '/wp-sitemap.xml'];
const LOC_REGEX = /<loc>\s*([^<]+?)\s*<\/loc>/g;

async function fetchSitemap(domain, path) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET', url: `https://${domain}${path}`,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; Googlebot/2.1; +http://www.google.com/bot.html)' },
      json: false, timeout: 15000
    });
    const urls = [];
    let m;
    while ((m = LOC_REGEX.exec(res)) !== null) {
      const u = m[1].trim();
      if (u.startsWith('http') && !u.endsWith('.xml')) urls.push(u);
    }
    LOC_REGEX.lastIndex = 0;
    return urls;
  } catch { return []; }
}

async function getExistingUrls(domain) {
  if (!ENV.SUPABASE_URL) return new Set();
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: `${ENV.SUPABASE_URL}/rest/v1/competitor_articles?competitor_domain=eq.${encodeURIComponent(domain)}&select=url`,
    headers: { apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}` },
    json: true, timeout: 10000
  }).catch(() => []);
  return new Set((Array.isArray(res) ? res : []).map(r => r.url));
}

async function processDomain(domain) {
  // Try each sitemap path, collect all unique article URLs
  const allUrls = new Set();
  for (const path of SITEMAP_PATHS) {
    const urls = await fetchSitemap.call(this, domain, path);
    urls.forEach(u => allUrls.add(u));
    if (allUrls.size > 0 && path === SITEMAP_PATHS[0]) break; // found primary sitemap
  }

  if (allUrls.size === 0) return { domain, found: 0, new: 0, status: 'no_sitemap' };

  // Filter out already-known URLs
  const existing = await getExistingUrls.call(this, domain);
  const newUrls = [...allUrls].filter(u => !existing.has(u)).slice(0, 50); // max 50 new per run

  // Send each new URL to content-extractor (fire-and-forget, don't wait)
  await Promise.allSettled(newUrls.map(url =>
    this.helpers.httpRequest({
      method: 'POST',
      url: 'http://localhost:5678/webhook/competitor/extract',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url, competitor_domain: domain }),
      json: true, timeout: 5000
    }).catch(() => null)
  ));

  return { domain, found: allUrls.size, new: newUrls.length, status: 'ok' };
}

const results = await Promise.allSettled(
  COMPETITORS.map(d => processDomain.call(this, d))
);

const summary = results.map((r, i) =>
  r.status === 'fulfilled' ? r.value : { domain: COMPETITORS[i], status: 'error', error: r.reason?.message?.slice(0, 100) }
);

const totalNew = summary.reduce((acc, r) => acc + (r.new || 0), 0);

return [{ json: { ok: true, competitors_checked: COMPETITORS.length, total_new_urls: totalNew, ran_at: new Date().toISOString(), details: summary } }];
